ambiguous_dsl.choice_dsl:
PREFIX : <http://ambrosia.example.org/entertainment#>
PREFIX p: <http://ambrosia.example.org/entertainment/prop#>
PREFIX xsd: <http://www.w3.org/2001/XMLSchema#>
CHOICE vague {
  component: { SELECT ?dancename ?culture ?popularity WHERE {
  ?dancetable a :Dance .
  ?dancetable p:DanceName ?dancename .
  ?dancetable p:Culture ?culture .
  ?dancetable p:Popularity ?popularity .
  ?dancetable p:Popularity ?popularity_b .
  ?dancetable p:Popularity ?popularity_o .
  FILTER(?popularity_b >= 70 && ?popularity_b <= 85)
}
ORDER BY DESC(?popularity_o) }
  full: { SELECT ?dancename ?culture ?geographical_area ?popularity WHERE {
  ?dancetable a :Dance .
  ?dancetable p:DanceName ?dancename .
  ?dancetable p:Culture ?culture .
  ?dancetable p:Geographical_Area ?geographical_area .
  ?dancetable p:Popularity ?popularity .
  ?dancetable p:Popularity ?popularity_b .
  ?dancetable p:Popularity ?popularity_o .
  FILTER(?popularity_b >= 70 && ?popularity_b <= 85)
}
ORDER BY DESC(?popularity_o) }
  component_2: { SELECT ?dancename ?geographical_area ?popularity WHERE {
  ?dancetable a :Dance .
  ?dancetable p:DanceName ?dancename .
  ?dancetable p:Geographical_Area ?geographical_area .
  ?dancetable p:Popularity ?popularity .
  ?dancetable p:Popularity ?popularity_b .
  ?dancetable p:Popularity ?popularity_o .
  FILTER(?popularity_b >= 70 && ?popularity_b <= 85)
}
ORDER BY DESC(?popularity_o) }
}

PREFIX : <http://ambrosia.example.org/entertainment#>
PREFIX p: <http://ambrosia.example.org/entertainment/prop#>
PREFIX xsd: <http://www.w3.org/2001/XMLSchema#>
CHOICE vague {
  component: { SELECT ?culture ?popularity WHERE {
  ?dancetable a :Dance .
  ?dancetable p:Culture ?culture .
  ?dancetable p:Popularity ?popularity .
  ?dancetable p:Popularity ?popularity_f .
  FILTER(xsd:double(?popularity_f) > 80)
} }
  full: { SELECT ?culture ?geographical_area ?popularity WHERE {
  ?dancetable a :Dance .
  ?dancetable p:Culture ?culture .
  ?dancetable p:Geographical_Area ?geographical_area .
  ?dancetable p:Popularity ?popularity .
  ?dancetable p:Popularity ?popularity_f .
  FILTER(xsd:double(?popularity_f) > 80)
} }
  component_2: { SELECT ?geographical_area ?popularity WHERE {
  ?dancetable a :Dance .
  ?dancetable p:Geographical_Area ?geographical_area .
  ?dancetable p:Popularity ?popularity .
  ?dancetable p:Popularity ?popularity_f .
  FILTER(xsd:double(?popularity_f) > 80)
} }
}
